Here's a typed, reusable button with a loading spinner:

```tsx
import { ButtonHTMLAttributes } from "react";

type Props = ButtonHTMLAttributes<HTMLButtonElement> & {
  loading?: boolean;
};

export function Button({ loading, children, disabled, ...rest }: Props) {
  return (
    <button disabled={loading || disabled} aria-busy={loading} {...rest}>
      {loading ? "Loading…" : children}
    </button>
  );
}
```
Usage: `<Button loading={isSaving} onClick={save}>Save</Button>`. Want a styled version with Tailwind?

ได้ครับ ใช้ไลบรารีมาตรฐาน ไม่ต้องติดตั้งอะไรเพิ่ม:

```python
import csv

def average_price(path: str, column: str = "price") -> float:
    total, count = 0.0, 0
    with open(path, newline="", encoding="utf-8") as f:
        for row in csv.DictReader(f):
            try:
                total += float(row[column]); count += 1
            except (KeyError, ValueError):
                continue
    return round(total / count, 2) if count else 0.0

if __name__ == "__main__":
    print(average_price("data.csv"))
```
